import{_ as s,c as a,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Superpowers 技能系统使用指南：调用规则、优先级与技能类型详解 | 教程","description":"学习 Superpowers 技能系统的核心规则，包括 1% 原则、完整调用流程、技能优先级顺序、刚性技能与柔性技能的区别。本教程详细讲解如何防止 AI 代理偷懒，让 AI 代理始终遵循 TDD、系统化调试等最佳实践。通过实战示例和常见错误分析，帮助你快速掌握技能调用规则，提升开发效率。","frontmatter":{"title":"Superpowers 技能系统使用指南：调用规则、优先级与技能类型详解 | 教程","sidebarTitle":"掌握技能调用","subtitle":"如何使用技能：调用规则与优先级","description":"学习 Superpowers 技能系统的核心规则，包括 1% 原则、完整调用流程、技能优先级顺序、刚性技能与柔性技能的区别。本教程详细讲解如何防止 AI 代理偷懒，让 AI 代理始终遵循 TDD、系统化调试等最佳实践。通过实战示例和常见错误分析，帮助你快速掌握技能调用规则，提升开发效率。","tags":["技能系统","调用规则","工作流"],"prerequisite":["start-verification"],"order":50},"headers":[],"relativePath":"zh/obra/superpowers/start/using-skills/index.md","filePath":"zh/obra/superpowers/start/using-skills/index.md"}'),i={name:"zh/obra/superpowers/start/using-skills/index.md"};function o(n,t,e,p,d,u){return r(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="如何使用技能-调用规则与优先级" tabindex="-1">如何使用技能：调用规则与优先级 <a class="header-anchor" href="#如何使用技能-调用规则与优先级" aria-label="Permalink to &quot;如何使用技能：调用规则与优先级&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>理解技能系统的核心规则（1% 原则）</li><li>掌握技能调用的正确时机和流程</li><li>了解技能优先级，知道先调用哪个技能</li><li>区分刚性技能和柔性技能，避免误用</li></ul><hr><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你是不是觉得 AI 代理有时候&quot;太聪明&quot;了？</p><ul><li>你问个简单问题，它直接给答案，结果不完整</li><li>你让它修 bug，它马上动手改，改完又引入新问题</li><li>你想让它遵循 TDD，它说&quot;这个很简单，不用测试&quot;</li></ul><p><strong>这些不是&quot;聪明&quot;，是&quot;偷懒&quot;</strong>——AI 代理会试图用最省力的方式完成任务。</p><p><strong>Superpowers 的解决方案</strong>：强制规则——即使只有 1% 的可能性，也必须检查技能。</p><hr><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p><strong>答案：每次任务前，无条件检查。</strong></p><p>具体场景：</p><ul><li>✅ 构建新功能</li><li>✅ 修复 Bug</li><li>✅ 回答技术问题</li><li>✅ 重构代码</li><li>✅ 编写测试</li><li>✅ 需要调试问题</li><li>✅ 探索代码库</li><li>✅ 收集信息</li></ul><p><strong>记住</strong>：技能检查必须在任何响应或行动之前完成，包括提问澄清之前。</p><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什么是技能系统" tabindex="-1">什么是技能系统？ <a class="header-anchor" href="#什么是技能系统" aria-label="Permalink to &quot;什么是技能系统？&quot;">​</a></h3><p><strong>技能系统</strong>是 Superpowers 的核心，它规定了 AI 代理在任何任务前必须先检查适用的技能。</p><p><strong>强制规则</strong>：</p><blockquote><p><strong>即使只有 1% 的可能性某个技能适用，也必须调用它。</strong></p><p><strong>如果适用技能，你没有选择——必须使用。</strong></p><p><strong>这不是可选项，不可谈判，也不能合理化逃避。</strong></p></blockquote><h3 id="为什么这么严格" tabindex="-1">为什么这么严格？ <a class="header-anchor" href="#为什么这么严格" aria-label="Permalink to &quot;为什么这么严格？&quot;">​</a></h3><p>因为 AI 代理的&quot;偷懒&quot;方式很多：</p><ul><li>&quot;这个很简单，不用技能&quot; → 可能在 5 分钟后变成复杂问题</li><li>&quot;我先看看代码&quot; → 但技能会告诉你如何正确地看</li><li>&quot;我先收集信息&quot; → 但技能会告诉你需要收集什么信息</li></ul><p><strong>技能系统防止所有这些偷懒行为</strong>，确保 AI 代理始终遵循最佳实践。</p><hr><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-理解调用流程" tabindex="-1">第 1 步：理解调用流程 <a class="header-anchor" href="#第-1-步-理解调用流程" aria-label="Permalink to &quot;第 1 步：理解调用流程&quot;">​</a></h3><p>当 AI 代理收到你的任务时，它必须遵循以下流程：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;用户消息接收&quot;] --&gt; B{可能适用任何技能吗?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|是的, 甚至只有1%| C[&quot;调用 Skill tool&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|确定不适用| H[&quot;响应 包括澄清问题&quot;]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;宣布: 使用 [技能] 来 [目的]&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E{有检查清单吗?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|有| F[&quot;创建 TodoWrite todo 每一项&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|没有| G[&quot;完全遵循技能&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#ffe5e5</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e5ffe5</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#e5e5ff</span></span></code></pre></div><p><strong>流程解释</strong>：</p><ol><li><strong>接收消息</strong>：AI 代理收到你的任务</li><li><strong>检查技能</strong>：判断是否有任何技能可能适用（即使 1% 的可能性）</li><li><strong>调用技能</strong>：使用 Skill tool 加载技能内容</li><li><strong>宣布使用</strong>：明确告诉你&quot;使用 [技能] 来 [目的]&quot;</li><li><strong>创建任务列表</strong>：如果技能有检查清单，为每一项创建 TodoWrite</li><li><strong>遵循技能</strong>：严格按照技能指示执行</li></ol><p><strong>关键点</strong>：</p><ul><li>步骤 2-3 必须在提问澄清之前完成</li><li>技能检查必须在任何行动之前完成</li></ul><hr><h3 id="第-2-步-识别-偷懒借口" tabindex="-1">第 2 步：识别&quot;偷懒借口&quot; <a class="header-anchor" href="#第-2-步-识别-偷懒借口" aria-label="Permalink to &quot;第 2 步：识别&quot;偷懒借口&quot;&quot;">​</a></h3><p>AI 代理可能会用各种借口逃避技能调用。识别这些借口，才能确保它不偷懒。</p><p><strong>常见错误想法 vs. 真相</strong>：</p><table tabindex="0"><thead><tr><th>AI 的想法</th><th>真相</th></tr></thead><tbody><tr><td>&quot;这只是个简单问题&quot;</td><td>问题也是任务。检查技能。</td></tr><tr><td>&quot;我需要更多上下文&quot;</td><td>技能检查在提问澄清之前。</td></tr><tr><td>&quot;我先看看代码&quot;</td><td>技能会告诉你如何探索代码。先检查技能。</td></tr><tr><td>&quot;我可以快速查 git 或文件&quot;</td><td>文件缺少对话上下文。先检查技能。</td></tr><tr><td>&quot;我先收集信息&quot;</td><td>技能会告诉你如何收集信息。先检查技能。</td></tr><tr><td>&quot;不需要正式技能&quot;</td><td>如果有技能存在，就用它。</td></tr><tr><td>&quot;我记得这个技能&quot;</td><td>技能会进化。读当前版本。</td></tr><tr><td>&quot;这不算任务&quot;</td><td>任何行动 = 任务。检查技能。</td></tr><tr><td>&quot;技能太复杂&quot;</td><td>简单的事情也会变复杂。用技能。</td></tr><tr><td>&quot;我先做这一件事&quot;</td><td>在做任何事之前，先检查技能。</td></tr><tr><td>&quot;这感觉很高效&quot;</td><td>无纪律的行动浪费时间。技能防止这个。</td></tr><tr><td>&quot;我知道这意味着什么&quot;</td><td>知道概念 ≠ 使用技能。调用它。</td></tr></tbody></table><p><strong>如果 AI 代理说这些话，立即要求它检查技能。</strong></p><hr><h3 id="第-3-步-理解技能优先级" tabindex="-1">第 3 步：理解技能优先级 <a class="header-anchor" href="#第-3-步-理解技能优先级" aria-label="Permalink to &quot;第 3 步：理解技能优先级&quot;">​</a></h3><p>当多个技能可能适用时，使用这个优先级顺序：</p><p><strong>1. 流程技能优先</strong></p><p>先确定如何处理任务：</p><ul><li><strong>brainstorming</strong>（创意设计）——需要澄清需求</li><li><strong>systematic-debugging</strong>（系统化调试）——需要修复 bug</li></ul><p><strong>2. 实现技能其次</strong></p><p>确定实施方式（示例可能随项目版本变化）：</p><ul><li><strong>test-driven-development</strong>（测试驱动开发）</li><li>其他实现相关技能</li></ul><p><strong>示例</strong>：</p><ul><li>&quot;我们来构建 X&quot; → 先 brainstorming（设计），然后实现技能</li><li>&quot;修复这个 bug&quot; → 先 systematic-debugging（调试），然后域特定技能</li></ul><p><strong>原则</strong>：先搞清楚怎么做（流程），再动手做（实现）。</p><hr><h3 id="第-4-步-区分刚性技能和柔性技能" tabindex="-1">第 4 步：区分刚性技能和柔性技能 <a class="header-anchor" href="#第-4-步-区分刚性技能和柔性技能" aria-label="Permalink to &quot;第 4 步：区分刚性技能和柔性技能&quot;">​</a></h3><p>不是所有技能都一样严格。</p><p><strong>刚性技能（Rigid）</strong>：</p><p>必须完全遵循，不要自行调整纪律：</p><ul><li><strong>test-driven-development</strong>（TDD）</li><li><strong>systematic-debugging</strong>（系统化调试）</li></ul><p>这些技能的核心是严格的流程和纪律，改变纪律就失去意义。</p><p><strong>柔性技能（Flexible）</strong>：</p><p>根据上下文调整原则：</p><ul><li><strong>brainstorming</strong>（创意设计）</li><li><strong>writing-plans</strong>（编写计划）</li></ul><p>技能内容会体现这种区别。</p><p><strong>原则</strong>：刚性技能必须严格遵循，柔性技能可以灵活应用。</p><hr><h3 id="第-5-步-实战练习" tabindex="-1">第 5 步：实战练习 <a class="header-anchor" href="#第-5-步-实战练习" aria-label="Permalink to &quot;第 5 步：实战练习&quot;">​</a></h3><p>现在你理解了规则，让我们看看 AI 代理应该怎么做。</p><p><strong>场景</strong>：你说&quot;给我写一个用户注册功能&quot;</p><p><strong>错误方式</strong>（偷懒）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI：好的，我来写注册功能...</span></span>
<span class="line"><span>[直接开始写代码]</span></span></code></pre></div><p><strong>正确方式</strong>（遵循技能）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI：让我检查一下是否有适用的技能。</span></span>
<span class="line"><span>[调用 brainstorming 技能]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI：使用 brainstorming 来澄清用户注册功能的需求。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在，让我先问几个问题来了解你的需求：</span></span>
<span class="line"><span>1. 需要哪些字段？</span></span>
<span class="line"><span>2. 需要邮箱验证吗？</span></span>
<span class="line"><span>3. 密码有什么要求？</span></span>
<span class="line"><span>[等待你的回答]</span></span></code></pre></div><p><strong>区别</strong>：</p><ul><li>错误方式：直接开干，可能写错</li><li>正确方式：先问清楚，确保符合需求</li></ul><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>确认 AI 代理的行为符合以下检查点：</p><ul><li>[ ] 任务开始前，AI 会说&quot;让我检查一下技能&quot;</li><li>[ ] 即使简单任务，AI 也会检查技能</li><li>[ ] AI 不会在提问澄清之前就开始行动</li><li>[ ] 多个技能适用时，AI 会按优先级顺序调用</li><li>[ ] 刚性技能（TDD、调试）会严格按照流程执行</li><li>[ ] AI 会明确告诉你&quot;使用 [技能] 来 [目的]&quot;</li></ul><p>如果以上都 OK，说明 AI 代理已经遵循技能调用规则！</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="ai-说我需要更多上下文" tabindex="-1">AI 说我需要更多上下文 <a class="header-anchor" href="#ai-说我需要更多上下文" aria-label="Permalink to &quot;AI 说我需要更多上下文&quot;">​</a></h3><p><strong>症状</strong>：AI 说&quot;我需要更多信息才能开始&quot;</p><p><strong>问题</strong>：技能检查应该在提问澄清之前</p><p><strong>解决</strong>：</p><ul><li>明确告诉 AI：&quot;在提问之前，先检查技能&quot;</li><li>技能可能会告诉你需要收集什么信息</li></ul><h3 id="ai-说任务很简单" tabindex="-1">AI 说任务很简单 <a class="header-anchor" href="#ai-说任务很简单" aria-label="Permalink to &quot;AI 说任务很简单&quot;">​</a></h3><p><strong>症状</strong>：AI 说&quot;这个很简单，不需要技能&quot;</p><p><strong>问题</strong>：简单任务也可能需要工作流</p><p><strong>解决</strong>：</p><ul><li>提醒 AI：&quot;即使 1% 的可能性，也必须检查技能&quot;</li><li>简单任务往往在过程中变复杂，技能会预防这个问题</li></ul><h3 id="ai-说它记得技能" tabindex="-1">AI 说它记得技能 <a class="header-anchor" href="#ai-说它记得技能" aria-label="Permalink to &quot;AI 说它记得技能&quot;">​</a></h3><p><strong>症状</strong>：AI 说&quot;我知道 TDD 是什么，不需要调用技能&quot;</p><p><strong>问题</strong>：技能会进化，记忆可能过时</p><p><strong>解决</strong>：</p><ul><li>要求 AI：&quot;使用 Skill tool 调用最新版本的技能&quot;</li><li>技能文件可能更新，AI 需要读取最新版本</li></ul><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>这节课你学会了：</p><ol><li><strong>核心规则</strong>：即使只有 1% 的可能性，也必须调用技能</li><li><strong>调用流程</strong>：接收消息 → 检查技能 → 调用 Skill tool → 宣布使用 → 遵循技能</li><li><strong>常见借口</strong>：识别 AI 的&quot;偷懒&quot;想法，防止逃避技能</li><li><strong>技能优先级</strong>：流程技能（brainstorming、debugging）优先，实现技能其次</li><li><strong>技能类型</strong>：刚性技能（TDD、调试）严格遵循，柔性技能灵活应用</li></ol><p><strong>核心思想</strong>：</p><ul><li>技能系统防止 AI 代理偷懒</li><li>强制规则确保始终遵循最佳实践</li><li>技能检查必须在任何行动之前完成</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../platforms/claude-code/">Claude Code 平台</a></strong>。</p><p>你会学到：</p><ul><li>Claude Code 的完整集成方式</li><li>如何使用 Skill tool 调用技能</li><li>钩子系统的自动加载机制</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>核心规则定义</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L6-L12" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>6-12</td></tr><tr><td>Skill tool 调用方式</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L16" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>16</td></tr><tr><td>调用流程图</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L26-L46" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>26-46</td></tr><tr><td>Red Flags（偷懒借口）</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L48-L65" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>48-65</td></tr><tr><td>技能优先级规则</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L67-L76" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>67-76</td></tr><tr><td>刚性/柔性技能区分</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L77-L81" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>77-81</td></tr><tr><td>用户指令说明</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L85-L88" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>85-88</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><strong>1% 原则</strong>：即使 1% 的可能性，也必须调用技能（<code>L7</code>）</li></ul><p><strong>关键规则</strong>：</p><ul><li><strong>强制规则</strong>：如果适用技能，AI 必须使用，不可谈判（<code>L9-L12</code>）</li><li><strong>流程优先</strong>：流程技能（brainstorming、debugging）→ 实现技能（<code>L71-L75</code>）</li></ul></details>`,108)])])}const c=s(i,[["render",o]]);export{h as __pageData,c as default};
